import json

def extract_resource_ids(template_str: str) -> list[str]:
    """
    Parse an AWS CloudFormation template in JSON format and extract all resource logical IDs.

    Args:
        template_str: A string containing a valid CloudFormation template in JSON format.

    Returns:
        A list of strings representing the logical IDs of all resources defined in the template.

    Raises:
        TypeError: If the input is None or not a string.
        ValueError: If the JSON is malformed, the root is not a dict, the 'Resources' key is missing,
                    the 'Resources' value is not a dict, or the 'Resources' dict is empty.
    """
    if template_str is None or not isinstance(template_str, str):
        raise TypeError(f"Input must be a string, got {type(template_str).__name__}")
    try:
        parsed = json.loads(template_str)
    except json.JSONDecodeError as e:
        raise ValueError(f"Malformed JSON: {e}")
    if not isinstance(parsed, dict):
        raise ValueError(f"Expected root JSON object to be a dict, got {type(parsed).__name__}")
    if "Resources" not in parsed:
        raise ValueError("Missing required top-level key 'Resources'")
    resources = parsed["Resources"]
    if not isinstance(resources, dict):
        raise ValueError(f"Expected 'Resources' to be a dict, got {type(resources).__name__}")
    if not resources:
        raise ValueError("'Resources' dict must not be empty")
    return list(resources.keys())

import re
import unittest

ARN_PATTERN = re.compile(
    r'^(?P<partition>arn:aws|arn:aws-us-gov|arn:aws-cn):iam::(?P<account_id>\d{12}):role/(?P<role_name>[a-zA-Z0-9_-]+(/[a-zA-Z0-9_-]+)*)$'
)

def match_arn(arn):
    if not isinstance(arn, str) or not arn:
        return None
    return ARN_PATTERN.match(arn)

class TestARNPattern(unittest.TestCase):
    def test_standard_aws(self):
        m = match_arn('arn:aws:iam::123456789012:role/MyRole')
        self.assertIsNotNone(m)
        self.assertEqual(m.group('partition'), 'arn:aws')
        self.assertEqual(m.group('account_id'), '123456789012')
        self.assertEqual(m.group('role_name'), 'MyRole')

    def test_govcloud(self):
        m = match_arn('arn:aws-us-gov:iam::123456789012:role/GovRole')
        self.assertIsNotNone(m)
        self.assertEqual(m.group('partition'), 'arn:aws-us-gov')
        self.assertEqual(m.group('account_id'), '123456789012')
        self.assertEqual(m.group('role_name'), 'GovRole')

    def test_china(self):
        m = match_arn('arn:aws-cn:iam::123456789012:role/CnRole')
        self.assertIsNotNone(m)
        self.assertEqual(m.group('partition'), 'arn:aws-cn')
        self.assertEqual(m.group('account_id'), '123456789012')
        self.assertEqual(m.group('role_name'), 'CnRole')

    def test_invalid_arn(self):
        self.assertIsNone(match_arn('arn:azure:iam::123456789012:role/MyRole'))

    def test_none_input(self):
        self.assertIsNone(match_arn(None))

    def test_empty_string(self):
        self.assertIsNone(match_arn(''))

    def test_consecutive_slashes(self):
        self.assertIsNone(match_arn('arn:aws:iam::123456789012:role/role//name'))

if __name__ == '__main__':
    unittest.main()

import json
from typing import Union


def flatten_metadata(data: Union[dict, str], prefix: str = '', _depth: int = 0) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters
    ----------
    data : Union[dict, str]
        The input metadata as a pre-parsed dict or a raw JSON string.
    prefix : str, optional
        The current key prefix used during recursion (default is '').
    _depth : int, optional
        Internal recursion depth counter (default is 0). Used to guard against
        excessive recursion. The maximum allowed depth is 19; depth 20 raises RecursionError.

    Returns
    -------
    dict
        A flat dictionary where nested keys are joined with dot-notation
        (e.g., 'network.interfaces.0.mac') and leaf values are preserved as-is.

    Raises
    ------
    TypeError
        If input is None or not a dict or string type. Raised unconditionally at
        every recursive call so that any non-dict value produces a clean TypeError.
    ValueError
        If a string input is not valid JSON.
    RecursionError
        If _depth reaches exactly 20 (i.e., _depth >= 20).

    Examples
    --------
    >>> metadata = {
    ...     "instanceId": "i-1234567890abcdef0",
    ...     "network": {
    ...         "interfaces": {
    ...             "0": {"mac": "02:42:ac:11:00:02"}
    ...         }
    ...     }
    ... }
    >>> flatten_metadata(metadata)
    {'instanceId': 'i-1234567890abcdef0', 'network.interfaces.0.mac': '02:42:ac:11:00:02'}
    """
    if data is None or not isinstance(data, (dict, str)):
        raise TypeError(f"Input must be a dict or JSON string, got {type(data).__name__}")
    if _depth >= 20:
        raise RecursionError("Maximum recursion depth of 19 exceeded (depth 20 is disallowed)")
    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON string: {e}")
        if not isinstance(data, dict):
            raise TypeError(f"Input must be a dict or JSON string, got {type(data).__name__}")
    result = {}
    for key, value in data.items():
        full_key = f"{prefix}.{key}" if prefix else key
        if isinstance(value, dict):
            result.update(flatten_metadata(value, full_key, _depth + 1))
        else:
            result[full_key] = value
    return result
